export function getSuitabilityColor(score: number): string {
  if (score >= 85) return '#22c55e';
  if (score >= 75) return '#eab308';
  return '#ef4444';
}

export function getSuitabilityLabel(score: number): string {
  if (score >= 85) return 'High';
  if (score >= 75) return 'Medium';
  return 'Low';
}

export function formatCO2(tons: number): string {
  if (tons >= 1_000_000) return `${(tons / 1_000_000).toFixed(1)}M`;
  if (tons >= 1_000) return `${(tons / 1_000).toFixed(0)}K`;
  return tons.toLocaleString();
}

// ── Derived helpers ──────────────────────────────────────────────────────────

export function isPlantRetired(plant: CoalPlant): boolean {
  return plant.status === 'Retired';
}

const SCENARIO_PARAMS = {
  optimistic:  { capex_factor: 0.85, lcoe_adj: -8,  npv_factor: 1.40 },
  base:        { capex_factor: 1.00, lcoe_adj:  0,  npv_factor: 1.00 },
  pessimistic: { capex_factor: 1.25, lcoe_adj: +12, npv_factor: 0.55 },
} as const;

type Scenario = 'optimistic' | 'base' | 'pessimistic';

export function getCapex(plant: CoalPlant, scenario: Scenario): number {
  return +(plant.capex_b * SCENARIO_PARAMS[scenario].capex_factor).toFixed(2);
}

export function getLCOE(plant: CoalPlant, scenario: Scenario): number {
  return +(plant.lcoe + SCENARIO_PARAMS[scenario].lcoe_adj).toFixed(2);
}

export function getNPV(plant: CoalPlant, scenario: Scenario): number {
  return +(plant.npv_b * SCENARIO_PARAMS[scenario].npv_factor).toFixed(3);
}

export function getAIDataCenters(plant: CoalPlant): number {
  return Math.floor(plant.capacity_mw / 150);
}

export function getMonteCarloRobustness(plant: CoalPlant): number {
  return Math.min(97, Math.round(plant.suitability_score * 0.72 + (plant.verified ? 28 : 20)));
}

export interface NationalStats {
  totalCapacityMW: number;
  aiCampuses: number;
  co2EliminatedMt: number;
  npvTotalB: number;
  cleanEnergyGapPct: number;
}

export function getNationalStats(plants: CoalPlant[], scenario: Scenario): NationalStats {
  const totalCapacityMW = plants.reduce((s, p) => s + p.capacity_mw, 0);
  const aiCampuses = plants.reduce((s, p) => s + getAIDataCenters(p), 0);
  const co2EliminatedMt = plants.reduce((s, p) => s + p.co2_reduction, 0) / 1e6;
  const npvTotalB = plants.reduce((s, p) => s + Math.max(0, getNPV(p, scenario)), 0);
  const annualMWh = plants.reduce((s, p) => s + p.annual_generation_mwh, 0);
  const cleanEnergyGapPct = Math.min(100, (annualMWh / 100_000_000) * 100);
  return {
    totalCapacityMW,
    aiCampuses,
    co2EliminatedMt: +co2EliminatedMt.toFixed(1),
    npvTotalB: +npvTotalB.toFixed(1),
    cleanEnergyGapPct: +cleanEnergyGapPct.toFixed(1),
  };
}
